  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Poulet au curry', null, null, null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Faire revenir l’oignon et l’ail dans une poêle"},{"kind":"li","value":"Ajouter le poulet et le faire dorer"},{"kind":"li","value":"Ajouter la pâte de curry et bien mélanger"},{"kind":"li","value":"Verser le lait de coco et laisser mijoter 10-15 minutes à feu doux"},{"kind":"li","value":"Cuire le riz selon les instructions du paquet"},{"kind":"li","value":"Servir chaud avec le riz"}]'::jsonb) returning id into v_id;
