  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Pâtes à la sauce tomate faite maison', null, null, null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Ajouter 2 ou 3 gousses d’ail"},{"kind":"li","value":"Ajouter un oignon"},{"kind":"li","value":"Faire revenir le tout dans une poêle jusqu’à ce que l’oignon et l’ail soient dorés"},{"kind":"li","value":"Ajouter la sauce tomate / coulis de tomate"},{"kind":"li","value":"Ajouter du basilic et des herbes"},{"kind":"li","value":"Faire cuire les pâtes comme mentionné en fonction des pâtes"},{"kind":"li","value":"**⭐ Garder 2 ou 3 cuillère d’eau des pâtes à incorporer dans la sauce**"},{"kind":"li","value":"Mettre les pâtes dans la poêle avec la préparation"},{"kind":"li","value":"✅ C’est prêt !"}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:pates-a-la-sauce-tomate-faite-maison', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Quiche lorraine avec salade', null, '🇫🇷 Français', 'https://www.marmiton.org/recettes/recette_quiche-lorraine_30283.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Préchauffer le four à 180°C"},{"kind":"li","value":"Etaler la pâte dans un moule"},{"kind":"li","value":"Piquer la pâte à la fourchette et parsemer de copeaux de beurre"},{"kind":"li","value":"Faire rissoler les lardons à la poêle et les éponger avec un feuille papier essuie-tout"},{"kind":"li","value":"Battre les oeufs, la crème fraiche et le lait"},{"kind":"li","value":"Ajouter les lardons"},{"kind":"li","value":"Assaisoner de sel, poivre, muscade"},{"kind":"li","value":"Verser sur la pâte"},{"kind":"li","value":"Cuire 45 à 50 min au four"},{"kind":"li","value":"**✅ C’est prêt !**"}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:quiche-lorraine-avec-salade', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Pilons de poulet au paprika et au curcuma', null, null, 'https://www.ricardocuisine.com/recettes/2076-pilons-de-poulet-au-paprika-et-au-curcuma', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Préchauffer le four à 180°C"},{"kind":"li","value":"Dans un bol mélanger le paprika, le curcuma et le sel"},{"kind":"li","value":"Dans un plat mélanger le poulet, les gousses d’ail. Saupoudrer du mélange d’épices. Poivrer et mélanger."},{"kind":"li","value":"Ajouter dans le four en faisant cuir le poulet de tous les côtés en le faisant baigner dans l’huile. Faire cuire environ 40 min"},{"kind":"li","value":"Accompagner de riz, de légumes, de quinoa…"}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:pilons-de-poulet-au-paprika-et-au-curcuma', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Tiramisu', null, null, null, array[(select id from _map where key='cat:dessert')]::uuid[], '[{"kind":"h","value":"🔻 Quantités"},{"kind":"li","value":"250g de mascarpone est suffisant"},{"kind":"li","value":"75g de sucre"},{"kind":"li","value":"2 oeufs (ou 3 petits)"},{"kind":"li","value":"L’équivalent d’un espresso d’alcool doux (amareto)"},{"kind":"li","value":"2 espresso de café (ou 1 café long)"},{"kind":"li","value":"Cacao amer"},{"kind":"li","value":"Petites amandes effilées"},{"kind":"li","value":"Penser à mettre le saladier de présentation au frigo pour le refroidir."},{"kind":"li","value":"Séparer les blancs des jaunes et placer les blancs dans un saladier et les jaunes dans un autre saladier."},{"kind":"li","value":"Pour les blancs"},{"kind":"li","value":"Ajouter une pincée de sel pour aider les oeufs à monter en neige"},{"kind":"li","value":"Battre les oeufs avec un batteur pour monter les blancs"},{"kind":"li","value":"⚠️ Il ne faut pas qu’il y ait de trace de jaune ou de gras dans les blancs sinon ça ne va pas monter."},{"kind":"li","value":"Pour les jaunes"},{"kind":"li","value":"Ajouter le sucre et battre les jaunes jusqu’à ce que ça blanchisse (ça devrait monter un peu aussi)"},{"kind":"li","value":"Il faut que ça fasse limite de la crème épaisse !"},{"kind":"li","value":"Ajouter le mascarpone et battre **à vitesse minimale** mais pas trop pour pas que le mascarpone ne se transforme en beurre."},{"kind":"li","value":"💡 Ou ne pas utiliser le batteur mais la cuillère à pâtissier !"},{"kind":"li","value":"Incorporer petit à petit les blancs dans les jaunes **sans casser les blancs montés** jusqu’à obtenir une mousser homogène."},{"kind":"p","value":"<aside>"},{"kind":"p","value":"⭐"},{"kind":"p","value":"Bien aller chercher les jaunes au fond du saladier et tourner avec une cuillère en bois."},{"kind":"p","value":"</aside>"},{"kind":"li","value":"Faire les cafés (ou un café long) et laisser refroidir + ajouter l’alcool sucré dedans (équivalent d’un espresso)"},{"kind":"li","value":"Verser le mélange dans une assiette creuse."},{"kind":"li","value":"Tremper les gateaux dans l’assiette (il faut vraiment faire un aller-retour pour pas que ça fasse de la bouilli) et les mettre dans le saladier de présentation."},{"kind":"li","value":"Faire ça plusieurs fois pour en mettre partout au fond du saladier + sur les bords pour que ça fasse joli."},{"kind":"li","value":"Verser toute la mousse (blancs + jaunes) dans le saladier de présentation."},{"kind":"li","value":"Mettre un papier plastique sur le dessus du saladier."},{"kind":"li","value":"Mettre le tout au frigo pendant plusieurs heures."},{"kind":"li","value":"Au moment de servir, utiliser une passoire pour saupoudrer le cacao amer et ajouter des amandes effilées préalablement revenues dans du beurre."}]'::jsonb) returning id into v_id;
