  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Pâtes à la sauce pesto & parmesan', null, null, null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Cuire les pâtes"},{"kind":"li","value":"Garder 1 ou 2 cuillères de l’eau des pâtes pour mettre dans une assiette creuse"},{"kind":"li","value":"Ajouter le pesto sur les pâtes et mélanger"},{"kind":"li","value":"Saupoudrer de parmesan"},{"kind":"li","value":"✅ C’est prêt !"}]'::jsonb) returning id into v_id;
