  insert into _map values ('recipe:hamburger-frites', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Tartiflette', null, null, 'https://cuisine.journaldesfemmes.fr/recette/315581-tartiflette', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Cuire les pommes de terre préalablement épluchées dans casserole."},{"kind":"li","value":"En parallèle, faire cuire les oignons dans le beurre puis passer à feu doux."},{"kind":"li","value":"Lorsque les oignons sont translucides, déglacer au vin blanc."},{"kind":"li","value":"Ajouter les lardons."},{"kind":"li","value":"Dans un plat allant au four, mettre une partie des oignons / lardons au fond, puis les pommes de terres, puis le reste des oignons / lardons."},{"kind":"li","value":"Ajouter le reblochon couper en deux au dessus du plat (croûte vers le haut)."},{"kind":"li","value":"Faire cuire environ 30 min à 180°C."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:tartiflette', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Croque Monsieur (Tomates, Pesto & Jambon de Parme)', null, null, 'https://www.marmiton.org/recettes/recette_croque-monsieur-au-pesto_70763.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Beurrer une tranche de pain de mie"},{"kind":"li","value":"Mettre le pesto du côté non beurré"},{"kind":"li","value":"Ajouter le jambon de parme"},{"kind":"li","value":"Ajouter la mozarella (ou autre fromage)"},{"kind":"li","value":"Ajouter les tranches de tomate coupées finement"},{"kind":"li","value":"Refermé avec la tranche de pain de mie beurrée"},{"kind":"li","value":"Faire cuire dans un appareil à croque monsieur"},{"kind":"li","value":"✅ C’est prêt !"}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:croque-monsieur-tomates-pesto-jambon-de-parme', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Gnocchi au pesto de basilic & épinards surgelés', null, null, null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Cuire les gnocchi**"},{"kind":"p","value":"Dans une grande casserole d’eau bouillante salée, fais cuire les gnocchi jusqu’à ce qu’ils remontent à la surface (2-3 min). Égoutte-les et mets-les de côté."},{"kind":"li","value":"**Préparer les épinards**"},{"kind":"p","value":"Dans une poêle, fais chauffer un filet d’huile d’olive et ajoute l’ail haché. Fais-le revenir quelques secondes."},{"kind":"p","value":"Ajoute les épinards surgelés, couvre et fais cuire à feu moyen pendant 5 à 8 min, jusqu’à ce qu’ils soient bien décongelés et que l’eau de cuisson soit évaporée."},{"kind":"li","value":"**Assembler le plat**"},{"kind":"p","value":"Ajoute les gnocchi cuits dans la poêle avec les épinards. Hors du feu, ajoute le pesto et mélange bien pour enrober le tout. Assaisonne avec sel et poivre."},{"kind":"li","value":"**Servir**"},{"kind":"p","value":"Dresse dans des assiettes et saupoudre de parmesan ou de levure maltée si tu veux une touche gourmande en plus."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:gnocchi-au-pesto-de-basilic-epinards-surgeles', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Pizza Margherita Maison (avec pâte toute prête)', null, null, null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Préchauffer le four à **220°C (chaleur tournante)**."},{"kind":"li","value":"Dérouler la pâte à pizza sur une plaque recouverte de papier cuisson."},{"kind":"li","value":"Étaler le coulis de tomate sur la pâte en laissant 1 cm de bord."},{"kind":"li","value":"Égoutter la mozzarella, la couper en tranches ou en petits morceaux, puis la répartir sur la pizza."},{"kind":"li","value":"Assaisonner avec du sel, du poivre, un filet d’huile d’olive, et quelques feuilles de basilic."},{"kind":"li","value":"(Optionnel) Parsemer un peu de parmesan râpé."},{"kind":"li","value":"Enfourner pendant **10 à 15 minutes**, jusqu’à ce que les bords soient dorés et la mozzarella bien fondue."},{"kind":"li","value":"Servir immédiatement avec quelques feuilles de basilic frais ajoutées après cuisson."},{"kind":"h","value":"💡 Astuces"},{"kind":"li","value":"Ajouter quelques tranches de tomates fraîches ou des tomates cerises coupées en deux pour plus de fraîcheur."},{"kind":"li","value":"Pour une pâte plus croustillante, précuire la pâte 5 minutes seule avant d’ajouter la garniture."}]'::jsonb) returning id into v_id;
