  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Filet de Cabillaud au Basilic & Haricots verts', null, null, 'https://www.marmiton.org/recettes/recette_cabillaud-a-la-sauce-basilic_29494.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Préparer la sauce** : émincer l’échalote et la faire revenir dans 50 g de beurre jusqu’à ce qu’elle soit translucide."},{"kind":"li","value":"Ajouter le vin blanc et laisser réduire de moitié."},{"kind":"li","value":"Incorporer la crème fraîche et laisser mijoter quelques minutes."},{"kind":"li","value":"Ajouter le basilic ciselé, saler et poivrer. Maintenir au chaud."},{"kind":"li","value":"**Cuire le poisson** : dans une poêle, faire fondre le reste du beurre et cuire les tranches de cabillaud 3 à 4 minutes de chaque côté, jusqu’à ce qu’elles soient bien dorées."},{"kind":"li","value":"Servir le poisson nappé de sauce au basilic."},{"kind":"li","value":"**Accompagnement** :"},{"kind":"li","value":"Accompagner de haricots verts"}]'::jsonb) returning id into v_id;
