  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Croquant aux amandes maison', null, null, 'https://www.marmiton.org/recettes/recette_croquants-aux-amandes-entieres_168701.aspx', array[(select id from _map where key='cat:dessert')]::uuid[], '[{"kind":"h","value":"🔻 Quantités"},{"kind":"p","value":"**→ Pour 6 personnes**"},{"kind":"li","value":"250g de sucre en poudre"},{"kind":"li","value":"400g de farine"},{"kind":"li","value":"2 cuillères à soupe de fleur d’oranger"},{"kind":"li","value":"4 oeufs (3 entiers + 1 jaune)"},{"kind":"li","value":"200g d’amandes entières"},{"kind":"li","value":"Battre les 3 œufs avec le sucre"},{"kind":"li","value":"Rajouter la fleur d''oranger, les amandes puis la farine"},{"kind":"li","value":"Finir de pétrir avec les mains et confectionnez 2 boudins un peu aplati"},{"kind":"li","value":"Badigeonner de jaune d''œuf dilué avec un peu d''eau"},{"kind":"li","value":"Passer au four à 200° (th.7) pendant 40mn et sortez du four"},{"kind":"li","value":"Pendant que c''est encore mou, couper les boudins en tranches d''1cm environ et repassez au four pendant 5mn pour sécher les gâteaux"}]'::jsonb) returning id into v_id;
