  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Wok de légumes et nouilles soba', null, '🌱 Végétarien', null, array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Préparer les légumes** :"},{"kind":"li","value":"Émincer l’oignon."},{"kind":"li","value":"Couper les brocolis en petites fleurettes."},{"kind":"li","value":"Éplucher et couper les carottes en fines lamelles (en julienne ou à l’économe)."},{"kind":"li","value":"Émincer les champignons."},{"kind":"li","value":"Hacher l’ail et râper le gingembre."},{"kind":"li","value":"**Cuire les nouilles soba** :"},{"kind":"li","value":"Suivre les instructions du paquet (généralement 5-6 min dans de l’eau bouillante salée)."},{"kind":"li","value":"Égoutter, rincer à l’eau froide et réserver."},{"kind":"li","value":"**Cuisson au wok** :"},{"kind":"li","value":"Chauffer l’huile dans un wok ou une grande poêle."},{"kind":"li","value":"Faire revenir l’oignon 2 min, puis ajouter l’ail et le gingembre."},{"kind":"li","value":"Ajouter les carottes, champignons et brocolis. Sauter 5 à 8 min à feu vif."},{"kind":"li","value":"Ajouter un petit filet d’eau si les légumes accrochent."},{"kind":"li","value":"**Mélanger avec les nouilles** :"},{"kind":"li","value":"Ajouter les nouilles soba cuites dans le wok."},{"kind":"li","value":"Verser la sauce soja et bien mélanger pendant 1 à 2 min pour réchauffer le tout."},{"kind":"li","value":"**Servir** :"},{"kind":"li","value":"Parsemer de graines de sésame."},{"kind":"li","value":"Ajouter de la coriandre fraîche ou des oignons verts si tu en as."},{"kind":"h","value":"**🌱 Suggestions**"},{"kind":"li","value":"Tu peux ajouter du **tofu grillé**, du **tempeh**, ou un œuf au plat pour une version plus complète."},{"kind":"li","value":"Variante express : remplacer les légumes frais par un mélange surgelé wok."}]'::jsonb) returning id into v_id;
