  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Chili con carne Maison', null, '🇺🇸 États-Unis', 'https://www.marmiton.org/recettes/recette_chili-con-carne-facile_15415.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Hacher l''oignon et l''ail et les faire dorer"},{"kind":"li","value":"Ajouter le boeuf haché et laisser cuire doucement 10 min"},{"kind":"li","value":"Mélanger le chili, le cumin, le concentré de tomates et incorporer le tout au boeuf."},{"kind":"li","value":"Ajouter les haricots, le bouillon."},{"kind":"li","value":"Saler et Poivrer"}]'::jsonb) returning id into v_id;
