  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Hachi parmentier de patate douce', null, '⚡ Protéiné, 🇫🇷 Français', 'https://www.instagram.com/reel/DB_yWCMozmW/?utm_source=ig_web_copy_link&igsh=NTc4MTIwNjQ2YQ==', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Purée**: Cuire les patates douces, écraser avec crème, beurre, sel."},{"kind":"li","value":"**Viande**: Faire revenir oignon + ail, ajouter bœuf, tomates, sauce tomate, sriracha; lier avec farine, finir au parmesan."},{"kind":"li","value":"**Montage**: Étaler viande dans un plat, couvrir de purée, saupoudrer de chapelure."},{"kind":"li","value":"**Gratin**: Enfourner jusqu’à **doré**."}]'::jsonb) returning id into v_id;
