  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Quiche Saumon Épinards avec salade', null, '🇫🇷 Français', 'https://www.marmiton.org/recettes/recette_quiche-au-saumon-et-aux-epinards_22164.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Préchauffer:** four à **Th 9** (four à gaz) et cuire 25–30 min."},{"kind":"li","value":"**Décongeler les épinards:** micro-ondes ou poêle, bien égoutter."},{"kind":"li","value":"**Cuire le saumon:** vapeur ou eau non salée, puis émietter."},{"kind":"li","value":"**Préparer l’appareil:** fouetter œufs, crème, parmesan, sel, poivre, pincée de muscade."},{"kind":"li","value":"**Foncer le moule:** disposer la pâte feuilletée."},{"kind":"li","value":"**Garnir:** étaler les épinards, ajouter le saumon, saupoudrer aneth et basilic."},{"kind":"li","value":"**Verser et cuire:** verser l’appareil, ajouter le gruyère (facultatif), enfourner jusqu’à dorure."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:quiche-saumon-epinards-avec-salade', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Fajitas', null, '⚡ Protéiné, 🇲🇽 Mexicain', 'https://www.oldelpaso.ch/recipes/chicken-fajitas-with-pepper-and-onion-filling', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"h","value":"✨ **Étapes**"},{"kind":"li","value":"**Préparer la garniture:** émincer poulet, poivrons et oignon."},{"kind":"li","value":"**Saisir le poulet:** 4 min à feu moyen avec un peu d’huile."},{"kind":"li","value":"**Assaisonner et mijoter:** ajouter le sachet d’épices et les légumes, cuire 3 min jusqu’à ce que la sauce nappe."},{"kind":"li","value":"**Chauffer les tortillas (au choix):**"},{"kind":"li","value":"**Four:** 200 °C, tortillas dans alu, 10 min."},{"kind":"li","value":"**Micro‑ondes:** percer le film, 35–40 s à 650–800 W, séparer et couvrir."},{"kind":"li","value":"**Garnir et plier:** à table, remplir les tortillas de garniture, ajouter la **Salsa Original Mild** et déguster."},{"kind":"h","value":"💡 **Astuce**"},{"kind":"li","value":"**Végétarien:** remplacer le poulet par aubergine ou courgette précuites."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:fajitas', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Risotto au chorizo', null, '🇮🇹 Italien', 'https://www.marmiton.org/recettes/recette_risotto-au-chorizo_17724.aspx', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Préparer le bouillon: porter 1,5 L d’eau à ébullition, dissoudre les 2 cubes."},{"kind":"li","value":"Tailler: émincer les échalotes; couper le chorizo en 2 ou en 4."},{"kind":"li","value":"Nacrer le riz: chauffer l’huile, faire revenir les échalotes 2 min; ajouter le riz cru et cuire jusqu’à translucide."},{"kind":"li","value":"Cuire au bouillon: ajouter le bouillon progressivement à hauteur, couvrir; compléter dès que le liquide baisse, goûter et poursuivre jusqu’à épuisement du bouillon."},{"kind":"li","value":"Finaliser: incorporer crème, sel, poivre, paprika, chorizo et parmesan; cuire encore 5 min."},{"kind":"li","value":"Servir: bien chaud."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:risotto-au-chorizo', v_id);
