  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Poulet rôti & pomme de terre', null, '🇫🇷 Français', 'https://jow.fr/recipes/poulet-roti-et-pomme-de-terre-8fba3kdsk4zrlk18130n', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"h","value":"✨ **Étapes**"},{"kind":"li","value":"**Préchauffer:** four à **200°C**. Écraser les gousses d’ail avec le plat du couteau."},{"kind":"li","value":"**Préparer le plat:** verser un filet d’huile d’olive au fond. Laver les pommes de terre (sans les éplucher)."},{"kind":"li","value":"**Disposer:** placer le poulet entier au centre, les pommes de terre autour et les gousses d’ail dans le plat."},{"kind":"li","value":"**Ajouter matière grasse:** déposer des tranches de beurre sur le poulet et ajouter un filet d’huile d’olive. Optionnel: ajouter thym ou romarin."},{"kind":"li","value":"**Assaisonner:** saler et poivrer généreusement. Enfourner **15 min à 200°C**."},{"kind":"li","value":"**Préparer le bouillon (optionnel):** faire chauffer 25 cl d’eau et y dissoudre un cube de bouillon."},{"kind":"li","value":"**Arroser et poursuivre la cuisson:** au bout de 15 min, sortir le plat, arroser d’eau ou de bouillon. Baisser le four à **180°C** et cuire env. **1 h 15** (compter ~30 min par 500 g de poulet)."},{"kind":"li","value":"**Pendant la cuisson:** arroser régulièrement le poulet avec le jus de cuisson et remuer les pommes de terre pour qu’elles dorent uniformément."},{"kind":"li","value":"**Finition:** sortir du four, couper les ficelles du poulet s’il est bridé, découper et servir bien chaud avec les pommes de terre."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:poulet-roti-pomme-de-terre', v_id);
  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Filet de sardines à l’huile d’olive et pain', null, null, null, array[(select id from _map where key='cat:entree-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"Prendre les filets de sardines et le pain mdr"}]'::jsonb) returning id into v_id;
