  insert into recipes (user_id, name, image, origin, link, categories, steps) values (v_user_id, 'Pan Con Tomate', null, '🇪🇸 Espagne', 'https://www.750g.com/pan-con-tomato-r200219.htm', array[(select id from _map where key='cat:plat-dejeuner-diner')]::uuid[], '[{"kind":"li","value":"**Préchauffer et griller le pain:** préchauffer le four à **180°C**. Couper le pain en tranches un peu épaisses et les faire légèrement griller au four pendant **5 min**."},{"kind":"li","value":"**Préparer tomate et ail:** couper la tomate en deux. Couper la gousse d’ail en deux."},{"kind":"li","value":"**Frotter le pain à l’ail:** frotter chaque tranche de pain chaud avec l’ail coupé."},{"kind":"li","value":"**Frotter avec la tomate:** frotter ensuite chaque tranche avec la tomate, en laissant tomber le jus et la pulpe pour bien **colorer le pain en rouge**."},{"kind":"li","value":"**Assaisonner:** ajouter un filet d’huile d’olive et un peu de fleur de sel sur chaque tartine."},{"kind":"li","value":"**Ajouter le jambon:** déchirer les tranches de jambon fumé en lanières avec les doigts et les déposer sur chaque tartine."},{"kind":"li","value":"**Finir avec le basilic:** ajouter quelques feuilles de basilic sur le dessus."},{"kind":"li","value":"**Servir:** déguster aussitôt, tant que le pain est encore tiède et croustillant."}]'::jsonb) returning id into v_id;
  insert into _map values ('recipe:pan-con-tomate', v_id);
